/**
 * US College Database for AGORA College Recruiting
 *
 * Fields:
 *   name        — Full college name
 *   alias       — Common abbreviation/nickname
 *   type        — 'public' | 'private'
 *   state       — Two-letter state code
 *   city        — City name
 *   region      — 'northeast' | 'southeast' | 'midwest' | 'southwest' | 'west'
 *   setting     — 'urban' | 'suburban' | 'rural'
 *   size        — 'small' (<5k) | 'medium' (5k-15k) | 'large' (>15k)
 *   enrollment  — Approximate undergraduate enrollment
 *   acceptance  — Acceptance rate (0-1)
 *   costIn      — In-state tuition + fees (annual, USD)
 *   costOut     — Out-of-state tuition + fees (annual, USD)
 *   sat25       — 25th percentile SAT total
 *   sat75       — 75th percentile SAT total
 *   act25       — 25th percentile ACT composite
 *   act75       — 75th percentile ACT composite
 *   rankTier    — 'top10' | 'top25' | 'top50' | 'top100' | 'top200' | 'other'
 *   rank        — Approximate national rank (1-1000)
 *   tags        — Array of feature tags
 *   app         — Application requirements object:
 *     .platform     — 'common-app' | 'common-app' | 'uc-app' | 'applytexas' | 'military' | 'direct'
 *     .testPolicy   — 'required' | 'optional' | 'blind' | 'free'
 *     .deadlineED   — Early Decision deadline (e.g. 'Nov 1')
 *     .deadlineED2  — Early Decision II deadline
 *     .deadlineEA   — Early Action deadline
 *     .deadlineRD   — Regular Decision deadline
 *     .rolling      — true if rolling admission
 *     .recLetters   — Number of recommendation letters required (0-3)
 *     .essays       — Number of supplemental essays
 *     .interview    — 'required' | 'recommended' | 'optional' | 'evaluative' | 'none'
 *     .specialReqs  — Array of special requirement strings
 *     .lookingFor   — What the school looks for in applicants
 */

