/**
 * Compute admission chance (0–100) based on student score vs college range
 */
export function computeAdmissionChance(studentScore, college, examType = 'sat') {
  const low = examType === 'act' ? college.act25 : college.sat25
  const high = examType === 'act' ? college.act75 : college.sat75
  if (!low || !high || !studentScore) return null

  const acceptance = college.acceptance
  const mid = (low + high) / 2
  const range = high - low

  // Base chance from score position
  let scoreRatio
  if (studentScore >= high) {
    // Above 75th — strong position
    const excess = Math.min((studentScore - high) / (range || 1), 1)
    scoreRatio = 0.75 + excess * 0.25
  } else if (studentScore >= mid) {
    // Between median and 75th
    scoreRatio = 0.5 + ((studentScore - mid) / (high - mid)) * 0.25
  } else if (studentScore >= low) {
    // Between 25th and median
    scoreRatio = 0.25 + ((studentScore - low) / (mid - low)) * 0.25
  } else {
    // Below 25th
    const deficit = Math.max(0, low - studentScore)
    const dropoff = Math.min(deficit / (range || 1), 2)
    scoreRatio = Math.max(0.02, 0.25 - dropoff * 0.15)
  }

  // Blend with acceptance rate — more selective schools weight test scores more
  const selectivityWeight = 1 - acceptance // Higher for more selective
  const chance = scoreRatio * (0.5 + selectivityWeight * 0.5) * 100

  // Clamp between 2% and 98%
  return Math.round(Math.min(98, Math.max(2, chance)))
}

/**
 * Get match tier label from chance
 */
export function getMatchTier(chance) {
  if (chance >= 70) return { label: 'Safety', color: '#059669', bg: 'rgba(16,185,129,.1)' }
  if (chance >= 45) return { label: 'Target', color: '#0ea5e9', bg: 'rgba(14,165,233,.1)' }
  if (chance >= 20) return { label: 'Reach', color: '#f59e0b', bg: 'rgba(245,158,11,.1)' }
  return { label: 'Long Reach', color: '#ef4444', bg: 'rgba(239,68,68,.1)' }
}
